   346→func newWorkloadIdentityTokenCredential(clientOpts *azcore.ClientOptions, workloadIdentityConfig *WorkloadIdentityConfig) (azcore.TokenCredential, error) {
   347→	opts := &azidentity.WorkloadIdentityCredentialOptions{
