   111→// azureADRoundTripper is used to store the roundtripper and the tokenprovider.
   112→type azureADRoundTripper struct {
   113→	next          http.RoundTripper
   114→	tokenProvider *tokenProvider
   115→}
   116→
   117→// tokenProvider is used to store and retrieve Azure AD accessToken.
   118→type tokenProvider struct {
   119→	// token is member used to store the current valid accessToken.
   120→	token string
   121→	// mu guards access to token.
   122→	mu sync.Mutex
   123→	// refreshTime is used to store the refresh time of the current valid accessToken.
   124→	refreshTime time.Time
   125→	// credentialClient is the Azure AD credential client that is being used to retrieve accessToken.
   126→	credentialClient azcore.TokenCredential
   127→	options          *policy.TokenRequestOptions
   128→}
   129→
   130→// Validate validates config values provided.
   131→func (c *AzureADConfig) Validate() error {
   132→	if c.Cloud == "" {
   133→		c.Cloud = AzurePublic
   134→	}
   135→
   136→	if c.Cloud != AzureChina && c.Cloud != AzureGovernment && c.Cloud != AzurePublic {
   137→		return errors.New("must provide a cloud in the Azure AD config")
   138→	}
   139→
   140→	authenticators := 0
   141→	if c.ManagedIdentity != nil {
   142→		authenticators++
   143→	}
   144→	if c.WorkloadIdentity != nil {
   145→		authenticators++
   146→	}
   147→	if c.OAuth != nil {
   148→		authenticators++
   149→	}
   150→	if c.SDK != nil {
   151→		authenticators++
   152→	}
   153→
   154→	if authenticators == 0 {
   155→		return errors.New("must provide an Azure Managed Identity, Azure Workload Identity, Azure OAuth or Azure SDK in the Azure AD config")
   156→	}
   157→	if authenticators > 1 {
   158→		return errors.New("cannot provide multiple authentication methods in the Azure AD config")
   159→	}
   160→
   161→	if c.ManagedIdentity != nil {
   162→		if c.ManagedIdentity.ClientID != "" {
   163→			_, err := uuid.Parse(c.ManagedIdentity.ClientID)
   164→			if err != nil {
   165→				return errors.New("the provided Azure Managed Identity client_id is invalid")
   166→			}
   167→		}
   168→	}
   169→
   170→	if c.WorkloadIdentity != nil {
   171→		if c.WorkloadIdentity.ClientID == "" {
   172→			return errors.New("must provide an Azure Workload Identity client_id in the Azure AD config")
   173→		}
   174→		if c.WorkloadIdentity.TenantID == "" {
   175→			return errors.New("must provide an Azure Workload Identity tenant_id in the Azure AD config")
   176→		}
   177→
   178→		if _, err := uuid.Parse(c.WorkloadIdentity.ClientID); err != nil {
   179→			return errors.New("the provided Azure Workload Identity client_id is invalid")
   180→		}
   181→		if _, err := uuid.Parse(c.WorkloadIdentity.TenantID); err != nil {
   182→			return errors.New("the provided Azure Workload Identity tenant_id is invalid")
   183→		}
   184→
   185→		if c.WorkloadIdentity.TokenFilePath == "" {
   186→			c.WorkloadIdentity.TokenFilePath = DefaultWorkloadIdentityTokenPath
   187→		}
   188→	}
   189→
   190→	if c.OAuth != nil {
   191→		if c.OAuth.ClientID == "" {
   192→			return errors.New("must provide an Azure OAuth client_id in the Azure AD config")
   193→		}
   194→		if c.OAuth.ClientSecret == "" {
   195→			return errors.New("must provide an Azure OAuth client_secret in the Azure AD config")
   196→		}
   197→		if c.OAuth.TenantID == "" {
   198→			return errors.New("must provide an Azure OAuth tenant_id in the Azure AD config")
   199→		}
   200→
   201→		if _, err := uuid.Parse(c.OAuth.ClientID); err != nil {
   202→			return errors.New("the provided Azure OAuth client_id is invalid")
   203→		}
   204→		if _, err := regexp.MatchString("^[0-9a-zA-Z-.]+$", c.OAuth.TenantID); err != nil {
   205→			return errors.New("the provided Azure OAuth tenant_id is invalid")
   206→		}
   207→	}
   208→
   209→	if c.SDK != nil {
   210→		if c.SDK.TenantID != "" {
   211→			if _, err := regexp.MatchString("^[0-9a-zA-Z-.]+$", c.SDK.TenantID); err != nil {
   212→				return errors.New("the provided Azure SDK tenant_id is invalid")
   213→			}
   214→		}
   215→	}
   216→
   217→	if c.Scope != "" {
   218→		if matched, err := regexp.MatchString("^[\\w\\s:/.\\-]+$", c.Scope); err != nil || !matched {
   219→			return errors.New("the provided scope contains invalid characters")
   220→		}
   221→	}
   222→
   223→	return nil
   224→}
   225→
   226→// UnmarshalYAML unmarshal the Azure AD config yaml.
   227→func (c *AzureADConfig) UnmarshalYAML(unmarshal func(any) error) error {
   228→	type plain AzureADConfig
   229→	*c = AzureADConfig{}
   230→	if err := unmarshal((*plain)(c)); err != nil {
   231→		return err
   232→	}
   233→	return c.Validate()
   234→}
   235→
   236→// NewAzureADRoundTripper creates round tripper adding Azure AD authorization to calls.
   237→func NewAzureADRoundTripper(cfg *AzureADConfig, next http.RoundTripper) (http.RoundTripper, error) {
   238→	if next == nil {
   239→		next = http.DefaultTransport
   240→	}
   241→
   242→	cred, err := newTokenCredential(cfg)
   243→	if err != nil {
   244→		return nil, err
   245→	}
   246→
   247→	tokenProvider, err := newTokenProvider(cfg, cred)
   248→	if err != nil {
   249→		return nil, err
   250→	}
   251→
   252→	rt := &azureADRoundTripper{
   253→		next:          next,
   254→		tokenProvider: tokenProvider,
   255→	}
   256→	return rt, nil
   257→}
   258→
   259→// RoundTrip sets Authorization header for requests.
   260→func (rt *azureADRoundTripper) RoundTrip(req *http.Request) (*http.Response, error) {
   261→	accessToken, err := rt.tokenProvider.getAccessToken(req.Context())
   262→	if err != nil {
   263→		return nil, err
   264→	}
   265→	bearerAccessToken := "Bearer " + accessToken
   266→	req.Header.Set("Authorization", bearerAccessToken)
   267→
   268→	return rt.next.RoundTrip(req)
   269→}
   270→
   271→// newTokenCredential returns a TokenCredential of different kinds like Azure Managed Identity, Workload Identity and Azure AD application.
   272→func newTokenCredential(cfg *AzureADConfig) (azcore.TokenCredential, error) {
   273→	var cred azcore.TokenCredential
   274→	var err error
   275→	cloudConfiguration, err := getCloudConfiguration(cfg.Cloud)
   276→	if err != nil {
   277→		return nil, err
   278→	}
   279→	clientOpts := &azcore.ClientOptions{
   280→		Cloud: cloudConfiguration,
   281→	}
   282→
   283→	if cfg.ManagedIdentity != nil {
   284→		managedIdentityConfig := &ManagedIdentityConfig{
   285→			ClientID: cfg.ManagedIdentity.ClientID,
   286→		}
   287→		cred, err = newManagedIdentityTokenCredential(clientOpts, managedIdentityConfig)
   288→		if err != nil {
   289→			return nil, err
   290→		}
   291→	}
   292→
   293→	if cfg.WorkloadIdentity != nil {
   294→		workloadIdentityConfig := &WorkloadIdentityConfig{
   295→			ClientID:      cfg.WorkloadIdentity.ClientID,
   296→			TenantID:      cfg.WorkloadIdentity.TenantID,
   297→			TokenFilePath: cfg.WorkloadIdentity.TokenFilePath,
   298→		}
   299→		cred, err = newWorkloadIdentityTokenCredential(clientOpts, workloadIdentityConfig)
   300→		if err != nil {
   301→			return nil, err
   302→		}
   303→	}
   304→
   305→	if cfg.OAuth != nil {
   306→		oAuthConfig := &OAuthConfig{
   307→			ClientID:     cfg.OAuth.ClientID,
   308→			ClientSecret: cfg.OAuth.ClientSecret,
   309→			TenantID:     cfg.OAuth.TenantID,
   310→		}
   311→		cred, err = newOAuthTokenCredential(clientOpts, oAuthConfig)
   312→		if err != nil {
   313→			return nil, err
   314→		}
   315→	}
   316→
   317→	if cfg.SDK != nil {
   318→		sdkConfig := &SDKConfig{
   319→			TenantID: cfg.SDK.TenantID,
   320→		}
   321→		cred, err = newSDKTokenCredential(clientOpts, sdkConfig)
   322→		if err != nil {
   323→			return nil, err
   324→		}
   325→	}
   326→
   327→	return cred, nil
   328→}
   329→
   330→// newManagedIdentityTokenCredential returns new Managed Identity token credential.
   331→func newManagedIdentityTokenCredential(clientOpts *azcore.ClientOptions, managedIdentityConfig *ManagedIdentityConfig) (azcore.TokenCredential, error) {
   332→	var opts *azidentity.ManagedIdentityCredentialOptions
   333→	if managedIdentityConfig.ClientID != "" {
   334→		clientID := azidentity.ClientID(managedIdentityConfig.ClientID)
   335→		opts = &azidentity.ManagedIdentityCredentialOptions{ClientOptions: *clientOpts, ID: clientID}
   336→	} else {
   337→		opts = &azidentity.ManagedIdentityCredentialOptions{ClientOptions: *clientOpts}
   338→	}
   339→	return azidentity.NewManagedIdentityCredential(opts)
   340→}
   341→
   342→// newWorkloadIdentityTokenCredential returns new Microsoft Entra Workload Identity token credential.
   343→//
   344→// For detailed setup instructions, see:
   345→// https://learn.microsoft.com/en-us/azure/azure-monitor/essentials/prometheus-metrics-enable-workload-identity
   346→func newWorkloadIdentityTokenCredential(clientOpts *azcore.ClientOptions, workloadIdentityConfig *WorkloadIdentityConfig) (azcore.TokenCredential, error) {
   347→	opts := &azidentity.WorkloadIdentityCredentialOptions{
   348→		ClientOptions: *clientOpts,
   349→		ClientID:      workloadIdentityConfig.ClientID,
   350→		TenantID:      workloadIdentityConfig.TenantID,
   351→		TokenFilePath: workloadIdentityConfig.TokenFilePath,
   352→	}
   353→
   354→	return azidentity.NewWorkloadIdentityCredential(opts)
   355→}
   356→
   357→// newOAuthTokenCredential returns new OAuth token credential.
   358→func newOAuthTokenCredential(clientOpts *azcore.ClientOptions, oAuthConfig *OAuthConfig) (azcore.TokenCredential, error) {
   359→	opts := &azidentity.ClientSecretCredentialOptions{ClientOptions: *clientOpts}
   360→	return azidentity.NewClientSecretCredential(oAuthConfig.TenantID, oAuthConfig.ClientID, oAuthConfig.ClientSecret, opts)
   361→}
   362→
   363→// newSDKTokenCredential returns new SDK token credential.
   364→func newSDKTokenCredential(clientOpts *azcore.ClientOptions, sdkConfig *SDKConfig) (azcore.TokenCredential, error) {
   365→	opts := &azidentity.DefaultAzureCredentialOptions{ClientOptions: *clientOpts, TenantID: sdkConfig.TenantID}
   366→	return azidentity.NewDefaultAzureCredential(opts)
   367→}
   368→
   369→// newTokenProvider helps to fetch accessToken for different types of credential. This also takes care of
   370→// refreshing the accessToken before expiry. This accessToken is attached to the Authorization header while making requests.
   371→func newTokenProvider(cfg *AzureADConfig, cred azcore.TokenCredential) (*tokenProvider, error) {
   372→	var scopes []string
   373→
   374→	// Use custom scope if provided, otherwise fallback to cloud-specific audience
   375→	if cfg.Scope != "" {
   376→		scopes = []string{cfg.Scope}
   377→	} else {
   378→		audience, err := getAudience(cfg.Cloud)
   379→		if err != nil {
   380→			return nil, err
   381→		}
   382→		scopes = []string{audience}
   383→	}
   384→
   385→	tokenProvider := &tokenProvider{
   386→		credentialClient: cred,
   387→		options:          &policy.TokenRequestOptions{Scopes: scopes},
   388→	}
   389→
   390→	return tokenProvider, nil
   391→}
   392→
   393→// getAccessToken returns the current valid accessToken.
   394→func (tokenProvider *tokenProvider) getAccessToken(ctx context.Context) (string, error) {
   395→	tokenProvider.mu.Lock()
   396→	defer tokenProvider.mu.Unlock()
   397→	if tokenProvider.valid() {
   398→		return tokenProvider.token, nil
   399→	}
   400→	err := tokenProvider.getToken(ctx)
   401→	if err != nil {
   402→		return "", errors.New("Failed to get access token: " + err.Error())
   403→	}
   404→	return tokenProvider.token, nil
   405→}
   406→
   407→// valid checks if the token in the token provider is valid and not expired.
   408→func (tokenProvider *tokenProvider) valid() bool {
   409→	if len(tokenProvider.token) == 0 {
   410→		return false
   411→	}
   412→	if tokenProvider.refreshTime.After(time.Now().UTC()) {
   413→		return true
   414→	}
   415→	return false
   416→}
   417→
   418→// getToken retrieves a new accessToken and stores the newly retrieved token in the tokenProvider.
   419→func (tokenProvider *tokenProvider) getToken(ctx context.Context) error {
   420→	accessToken, err := tokenProvider.credentialClient.GetToken(ctx, *tokenProvider.options)
   421→	if err != nil {
   422→		return err
   423→	}
   424→	if len(accessToken.Token) == 0 {
   425→		return errors.New("access token is empty")
   426→	}
   427→
   428→	tokenProvider.token = accessToken.Token
   429→	err = tokenProvider.updateRefreshTime(accessToken)
   430→	if err != nil {
   431→		return err
   432→	}
   433→	return nil
   434→}
   435→
   436→// updateRefreshTime handles logic to set refreshTime. The refreshTime is set at half the duration of the actual token expiry.
   437→func (tokenProvider *tokenProvider) updateRefreshTime(accessToken azcore.AccessToken) error {
   438→	tokenExpiryTimestamp := accessToken.ExpiresOn.UTC()
   439→	deltaExpirytime := time.Now().Add(time.Until(tokenExpiryTimestamp) / 2)
   440→	if !deltaExpirytime.After(time.Now().UTC()) {
   441→		return errors.New("access token expiry is less than the current time")
   442→	}
   443→	tokenProvider.refreshTime = deltaExpirytime
   444→	return nil
   445→}
   446→
   447→// getAudience returns audiences for different clouds.
   448→func getAudience(cloud string) (string, error) {
   449→	switch strings.ToLower(cloud) {
   450→	case strings.ToLower(AzureChina):
   451→		return IngestionChinaAudience, nil
   452→	case strings.ToLower(AzureGovernment):
   453→		return IngestionGovernmentAudience, nil
   454→	case strings.ToLower(AzurePublic):
   455→		return IngestionPublicAudience, nil
   456→	default:
   457→		return "", errors.New("Cloud is not specified or is incorrect: " + cloud)
   458→	}
   459→}
   460→
   461→// getCloudConfiguration returns the cloud Configuration which contains AAD endpoint for different clouds.
   462→func getCloudConfiguration(c string) (cloud.Configuration, error) {
   463→	switch strings.ToLower(c) {
   464→	case strings.ToLower(AzureChina):
   465→		return cloud.AzureChina, nil
   466→	case strings.ToLower(AzureGovernment):
   467→		return cloud.AzureGovernment, nil
   468→	case strings.ToLower(AzurePublic):
   469→		return cloud.AzurePublic, nil
   470→	default:
   471→		return cloud.Configuration{}, errors.New("Cloud is not specified or is incorrect: " + c)
   472→	}
   473→}
